class Solution:
    def countWays(self, nums):
        n = len(nums)
        count = 0
        for mask in range(1 << n):
            k = bin(mask).count('1')
            ok = True
            for i in range(n):
                selected = (mask >> i) & 1
                if selected:
                    if not (k > nums[i]):
                        ok = False
                        break
                else:
                    if not (k < nums[i]):
                        ok = False
                        break
            if ok:
                count += 1
        return count

