class Solution:
    def countWays(self, nums):
        arr = sorted(nums)
        n = len(arr)
        count = 0
        for k in range(n + 1):
            left_ok = (k == 0) or (arr[k - 1] < k)
            right_ok = (k == n) or (arr[k] > k)
            if left_ok and right_ok:
                count += 1
        return count

