var countWays = function(nums) {
    const arr = nums.slice().sort((a, b) => a - b);
    const n = arr.length;
    let count = 0;
    for (let k = 0; k <= n; k++) {
        const leftOk = (k === 0) || (arr[k - 1] < k);
        const rightOk = (k === n) || (arr[k] > k);
        if (leftOk && rightOk) count++;
    }
    return count;
};
